Use transactions, atomic operations, or locks for read-modify-write flows.
# Category: race_condition

import akka.actor.{Actor, ActorSystem, Props}
import scala.concurrent.duration._

class AccountBalanceActor extends Actor {
  var balance = 0.0

  override def receive: Receive = {
    case Deposit(amount) =>
      balance += amount
      println(s"Deposited $amount, new balance is $balance")

    case Withdraw(amount) if balance >= amount =>
      balance -= amount
      println(s"Withdrew $amount, new balance is $balance")
    case Withdraw(_) => println("Insufficient funds")
  }
}

object AccountBalanceActor {
  def props: Props = Props[AccountBalanceActor]

  def main(args: Array[String]): Unit = {
    val system = ActorSystem("account-balance-system")
    val actor = system.actorOf(AccountBalanceActor.props)

    // Simulate concurrent transactions
    for (i <- 1 to 10) {
      system.scheduler.scheduleOnce(100.millis, actor, Deposit(i))
      system.scheduler.scheduleOnce(150.millis, actor, Withdraw(i))
    }
  }

  case class Deposit(amount: Double)
  case class Withdraw(amount: Double)
}